Here's a solid pattern for testing async code with MSTest, using `MockHttpMessageHandler` to control responses:

```csharp
[TestClass]
public class DataFetcherTests
{
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new MockHttpMessageHandler("hello", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnHttpError()
    {
        var handler = new MockHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_HonoursCancellation()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        var handler = new MockHttpMessageHandler("data", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)] // failsafe: test itself times out after 3s
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        var handler = new MockHttpMessageHandler("fast", HttpStatusCode.OK);
        using var client = new HttpClient(handler) { Timeout = TimeSpan.FromSeconds(1) };
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("fast", result);
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsOnTimeout_WhenServerIsSlow()
    {
        var handler = new MockHttpMessageHandler("slow", HttpStatusCode.OK,
            delay: TimeSpan.FromSeconds(10));
        using var client = new HttpClient(handler) { Timeout = TimeSpan.FromMilliseconds(100) };
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com"));
    }
}
```

And the lightweight mock handler:

```csharp
public class MockHttpMessageHandler : HttpMessageHandler
{
    private readonly string _content;
    private readonly HttpStatusCode _statusCode;
    private readonly TimeSpan _delay;

    public MockHttpMessageHandler(string content, HttpStatusCode statusCode,
        TimeSpan delay = default)
    {
        _content = content;
        _statusCode = statusCode;
        _delay = delay;
    }

    protected override async Task<HttpResponseMessage> SendAsync(
        HttpRequestMessage request, CancellationToken cancellationToken)
    {
        if (_delay > TimeSpan.Zero)
            await Task.Delay(_delay, cancellationToken);

        cancellationToken.ThrowIfCancellationRequested();

        return new HttpResponseMessage(_statusCode)
        {
            Content = new StringContent(_content)
        };
    }
}
```

**Key patterns to note:**

- **`[Timeout(ms)]`** — MSTest's built-in per-test timeout; acts as a safety net against hanging tests.
- **Pre-cancelled token** — simplest way to verify cancellation is respected without real delays.
- **Simulated slow server** — pair a short `HttpClient.Timeout` with a long `Task.Delay` in the handler to test timeout behavior. `HttpClient` surfaces timeouts as `TaskCanceledException`.
- **No `Task.Result` / `.Wait()`** — always `await`; blocking on async code risks deadlocks in test runners.
